import heapq

class SeatReservationManager:
    def __init__(self, n: int):
        self.available_seats = [i for i in range(1, n + 1)]
        heapq.heapify(self.available_seats)
        self.reserved = set()

    def reserve_seat(self) -> int:
        if not self.available_seats:
            return -1 # No seats available

        seat_number = heapq.heappop(self.available_seats)
        self.reserved.add(seat_number)
        return seat_number

    def release_seat(self, seat_number: int) -> None:
        if seat_number in self.reserved:
            self.reserved.remove(seat_number)
            heapq.heappush(self.available_seats, seat_number)
